// ── Graphe de courbe pour visites/jour ────────────────────────────────────────
function LineChart({ data }: { data: { jour: string; visites: number; visiteurs: number }[] }) {
  const [hover, setHover] = useState<number | null>(null);
  if (!data.length) return null;

  const W = 780, H = 200, PAD = { top: 16, right: 20, bottom: 32, left: 48 };
  const innerW = W - PAD.left - PAD.right;
  const innerH = H - PAD.top - PAD.bottom;
  const maxV = Math.max(...data.map(d => d.visites), 1);

  const xPos = (i: number) => PAD.left + (i / (data.length - 1)) * innerW;
  const yPos = (v: number) => PAD.top + innerH - (v / maxV) * innerH;

  const pathVisites  = data.map((d, i) => `${i === 0 ? 'M' : 'L'}${xPos(i)},${yPos(d.visites)}`).join(' ');
  const pathVis      = data.map((d, i) => `${i === 0 ? 'M' : 'L'}${xPos(i)},${yPos(d.visiteurs)}`).join(' ');
  const areaVisites  = `${pathVisites} L${xPos(data.length-1)},${PAD.top+innerH} L${xPos(0)},${PAD.top+innerH} Z`;

  // Ticks Y
  const yTicks = [0, 0.25, 0.5, 0.75, 1].map(f => Math.round(maxV * f));

  return (
    <div style={{ overflowX: 'auto' }}>
      <svg width={W} height={H} style={{ display: 'block' }}>
        <defs>
          <linearGradient id="areaGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%"   stopColor={T.accent} stopOpacity="0.3" />
            <stop offset="100%" stopColor={T.accent} stopOpacity="0.02" />
          </linearGradient>
        </defs>

        {/* Grid */}
        {yTicks.map((tick, i) => (
          <g key={i}>
            <line x1={PAD.left} y1={yPos(tick)} x2={W-PAD.right} y2={yPos(tick)} stroke="#e5e7eb" strokeWidth="1" strokeDasharray="4 4" />
            <text x={PAD.left - 6} y={yPos(tick) + 4} fontSize="10" fill={T.textLight} textAnchor="end">{fmt(tick)}</text>
          </g>
        ))}

        {/* Area */}
        <path d={areaVisites} fill="url(#areaGrad)" />

        {/* Lignes */}
        <path d={pathVisites} fill="none" stroke={T.accent} strokeWidth="2.5" strokeLinejoin="round" />
        <path d={pathVis}     fill="none" stroke="#10b981"  strokeWidth="1.5" strokeLinejoin="round" strokeDasharray="5 3" />

        {/* Points hover */}
        {data.map((d, i) => (
          <g key={i} onMouseEnter={() => setHover(i)} onMouseLeave={() => setHover(null)}>
            <circle cx={xPos(i)} cy={yPos(d.visites)} r={hover === i ? 5 : 3}
              fill={T.accent} stroke="white" strokeWidth="2" style={{ transition: 'r 0.1s' }} />
            {hover === i && (
              <g>
                <rect x={xPos(i) - 50} y={yPos(d.visites) - 48} width="100" height="42" rx="6"
                  fill={T.sidebar} />
                <text x={xPos(i)} y={yPos(d.visites) - 32} fontSize="10" fill="white" textAnchor="middle" fontWeight="bold">
                  {d.jour.slice(5)}
                </text>
                <text x={xPos(i)} y={yPos(d.visites) - 18} fontSize="10" fill="#93c5fd" textAnchor="middle">
                  {fmt(d.visites)} visites
                </text>
                <text x={xPos(i)} y={yPos(d.visites) - 6} fontSize="10" fill="#6ee7b7" textAnchor="middle">
                  {fmt(d.visiteurs)} visiteurs
                </text>
              </g>
            )}
          </g>
        ))}

        {/* X labels — afficher 1 sur 5 */}
        {data.map((d, i) => i % 5 === 0 && (
          <text key={i} x={xPos(i)} y={H - 6} fontSize="10" fill={T.textLight} textAnchor="middle">
            {d.jour.slice(5)}
          </text>
        ))}
      </svg>

      {/* Légende */}
      <div style={{ display: 'flex', gap: '20px', marginTop: '8px', paddingLeft: `${PAD.left}px` }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
          <div style={{ width: '20px', height: '3px', backgroundColor: T.accent, borderRadius: '2px' }} />
          <span style={{ fontSize: '11px', color: T.textLight }}>Visites</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
          <div style={{ width: '20px', height: '2px', backgroundColor: '#10b981', borderRadius: '2px', backgroundImage: 'repeating-linear-gradient(90deg,#10b981,#10b981 5px,transparent 5px,transparent 8px)' }} />
          <span style={{ fontSize: '11px', color: T.textLight }}>Visiteurs uniques</span>
        </div>
      </div>
    </div>
  );
}

// ── Donut chart ───────────────────────────────────────────────────────────────
function DonutChart({ data, total, couleurs }: { data: { label: string; value: number }[]; total: number; couleurs: string[] }) {
  const [hovered, setHovered] = useState<number | null>(null);
  const R = 60, r = 35, cx = 80, cy = 80;
  let startAngle = -Math.PI / 2;

  const slices = data.map((d, i) => {
    const pct = total > 0 ? d.value / total : 0;
    const angle = pct * 2 * Math.PI;
    const x1 = cx + R * Math.cos(startAngle);
    const y1 = cy + R * Math.sin(startAngle);
    startAngle += angle;
    const x2 = cx + R * Math.cos(startAngle);
    const y2 = cy + R * Math.sin(startAngle);
    const xi1 = cx + r * Math.cos(startAngle);
    const yi1 = cy + r * Math.sin(startAngle);
    const xi2 = cx + r * Math.cos(startAngle - angle);
    const yi2 = cy + r * Math.sin(startAngle - angle);
    const large = angle > Math.PI ? 1 : 0;
    return { path: `M${x1},${y1} A${R},${R} 0 ${large},1 ${x2},${y2} L${xi1},${yi1} A${r},${r} 0 ${large},0 ${xi2},${yi2} Z`, pct, d };
  });

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '24px' }}>
      <svg width="160" height="160">
        {slices.map((s, i) => (
          <path key={i} d={s.path} fill={couleurs[i % couleurs.length]}
            opacity={hovered === null || hovered === i ? 1 : 0.5}
            style={{ cursor: 'default', transition: 'opacity 0.2s' }}
            onMouseEnter={() => setHovered(i)}
            onMouseLeave={() => setHovered(null)}
          />
        ))}
        <text x={cx} y={cy - 8} textAnchor="middle" fontSize="18" fontWeight="800" fill={T.text}>
          {hovered !== null ? `${Math.round(slices[hovered].pct * 100)}%` : fmt(total)}
        </text>
        <text x={cx} y={cy + 10} textAnchor="middle" fontSize="10" fill={T.textLight}>
          {hovered !== null ? data[hovered].label : 'total'}
        </text>
      </svg>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
        {data.map((d, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '8px' }}
            onMouseEnter={() => setHovered(i)} onMouseLeave={() => setHovered(null)}>
            <div style={{ width: '10px', height: '10px', borderRadius: '50%', backgroundColor: couleurs[i % couleurs.length], flexShrink: 0 }} />
            <span style={{ fontSize: '12px', color: T.text, fontWeight: hovered === i ? '700' : '500' }}>{d.label}</span>
            <span style={{ fontSize: '12px', color: T.textLight, marginLeft: 'auto' }}>{fmt(d.value)}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

