// Centres approximatifs de chaque province pour les bulles (dans le viewBox 793x1032)
const PROVINCE_CENTERS: Record<string, [number, number]> = {
  bc:  [130,  870],
  ab:  [248,  900],
  sk:  [325,  900],
  mb:  [430,  910],
  on:  [530,  950],
  qc:  [690,  840],
  nb:  [668,  985],
  ns:  [700,  995],
  pe:  [703,  973],
  nl:  [725,  870],
  yt:  [110,  700],
  nt:  [230,  730],
  nu:  [430,  650],
};

function CarteCanada({ provinces }: { provinces: { code: string; nom: string; x: number; y: number; visites: number }[] }) {
  const [hover, setHover] = useState<string | null>(null);
  const max = Math.max(...provinces.map(p => p.visites), 1);

  // Map code province → données
  const provMap = Object.fromEntries(provinces.map(p => [p.code.toLowerCase(), p]));

  // Noms affichés au survol
  const NOMS: Record<string, string> = {
    bc: 'Colombie-Britannique', ab: 'Alberta', sk: 'Saskatchewan', mb: 'Manitoba',
    on: 'Ontario', qc: 'Québec', nb: 'Nouveau-Brunswick', ns: 'Nouvelle-Écosse',
    pe: 'Î.-P.-É.', nl: 'Terre-Neuve', yt: 'Yukon', nt: 'T.-N.-O.', nu: 'Nunavut',
  };

  return (
    <div style={{ position: 'relative', backgroundColor: '#f0f7ff', borderRadius: '12px', padding: '20px', border: `1px solid ${T.border}` }}>
      <div style={{ position: 'relative', width: '100%' }}>
        {/* viewBox calé sur le vrai espace de coordonnées du package @svg-maps/canada */}
        <svg viewBox="40 580 760 460" style={{ width: '100%', display: 'block' }}>

          {/* Provinces/territoires colorés */}
          {Object.entries(PROVINCE_PATHS).map(([code, d]) => {
            const prov = provMap[code];
            const pct = prov ? prov.visites / max : 0;
            const fill = prov && prov.visites > 0
              ? `rgba(45,106,159,${0.15 + pct * 0.75})`
              : '#e8f0f8';
            const isHov = hover === code;
            return (
              <path key={code} d={d}
                fill={isHov ? T.accent : fill}
                stroke="white"
                strokeWidth="1"
                style={{ cursor: 'default', transition: 'fill 0.2s' }}
                onMouseEnter={() => setHover(code)}
                onMouseLeave={() => setHover(null)}
              />
            );
          })}

          {/* Bulles de visites */}
          {Object.entries(PROVINCE_CENTERS).map(([code, [cx, cy]]) => {
            const prov = provMap[code];
            if (!prov || prov.visites === 0) return null;
            const r = 14 + (prov.visites / max) * 22;
            const isHov = hover === code;
            const nom = NOMS[code] || code.toUpperCase();
            return (
              <g key={`b-${code}`}
                onMouseEnter={() => setHover(code)}
                onMouseLeave={() => setHover(null)}
                style={{ cursor: 'default' }}>
                <circle cx={cx} cy={cy} r={r}
                  fill={isHov ? '#1a4f7a' : T.accent}
                  stroke="white" strokeWidth="2"
                  opacity="0.92"
                  style={{ transition: 'all 0.2s' }}
                />
                <text x={cx} y={cy + 1} textAnchor="middle" dominantBaseline="middle"
                  fontSize={Math.max(7, r * 0.5)} fontWeight="800" fill="white">
                  {fmt(prov.visites)}
                </text>
                {isHov && (
                  <g>
                    <rect x={cx - 55} y={cy - r - 36} width="110" height="30" rx="6" fill={T.sidebar} />
                    <text x={cx} y={cy - r - 25} textAnchor="middle" fontSize="9" fill="white" fontWeight="700">
                      {nom}
                    </text>
                    <text x={cx} y={cy - r - 13} textAnchor="middle" fontSize="8" fill="#93c5fd">
                      {fmt(prov.visites)} visites
                    </text>
                  </g>
                )}
              </g>
            );
          })}

          {/* Labels codes provinces (toujours visibles) */}
          {Object.entries(PROVINCE_CENTERS).map(([code, [cx, cy]]) => {
            const prov = provMap[code];
            if (prov && prov.visites > 0) return null; // masqué si bulle présente
            return (
              <text key={`lbl-${code}`} x={cx} y={cy} textAnchor="middle" dominantBaseline="middle"
                fontSize="8" fontWeight="700" fill={hover === code ? 'white' : T.textLight}
                style={{ pointerEvents: 'none', userSelect: 'none' }}>
                {code.toUpperCase()}
              </text>
            );
          })}
        </svg>

        {/* Tooltip province au survol (sans bulle) */}
        {hover && !provMap[hover]?.visites && (
          <div style={{
            position: 'absolute', top: '10px', left: '50%', transform: 'translateX(-50%)',
            backgroundColor: T.sidebar, color: 'white', borderRadius: '8px', padding: '6px 14px',
            fontSize: '12px', fontWeight: '700', pointerEvents: 'none',
            boxShadow: '0 4px 16px rgba(0,0,0,0.3)',
          }}>
            {NOMS[hover] || hover.toUpperCase()} — aucune visite
          </div>
        )}
      </div>

      {/* Légende intensité couleur */}
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px', marginTop: '12px' }}>
        <span style={{ fontSize: '11px', color: T.textLight }}>Peu de visites</span>
        {[0.15, 0.35, 0.55, 0.75, 0.9].map((o, i) => (
          <div key={i} style={{ width: '20px', height: '12px', borderRadius: '3px', backgroundColor: `rgba(45,106,159,${o})` }} />
        ))}
        <span style={{ fontSize: '11px', color: T.textLight }}>Beaucoup</span>
      </div>
    </div>
  );
}

// ── KPI Card ──────────────────────────────────────────────────────────────────
function KPI({ icon, titre, valeur, sous, couleur, tendance }: {
  icon: string; titre: string; valeur: string; sous: string; couleur: string; tendance?: { val: string; positif: boolean };
}) {
  return (
    <div style={{ backgroundColor: T.card, borderRadius: '12px', border: `1px solid ${T.border}`, padding: '20px 24px', position: 'relative', overflow: 'hidden' }}>
      <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '3px', backgroundColor: couleur }} />
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px' }}>
        <div style={{ width: '42px', height: '42px', borderRadius: '10px', backgroundColor: couleur + '18', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '20px' }}>{icon}</div>
        {tendance && (
          <span style={{ fontSize: '11px', fontWeight: '700', color: tendance.positif ? T.success : T.danger, backgroundColor: tendance.positif ? '#dcfce7' : '#fee2e2', padding: '3px 8px', borderRadius: '20px' }}>
            {tendance.positif ? '↑' : '↓'} {tendance.val}
          </span>
        )}
      </div>
      <p style={{ fontSize: '26px', fontWeight: '800', color: T.text, margin: '0 0 3px 0' }}>{valeur}</p>
      <p style={{ fontSize: '12px', fontWeight: '600', color: T.textLight, margin: '0 0 1px 0' }}>{titre}</p>
      <p style={{ fontSize: '11px', color: '#aaa', margin: 0 }}>{sous}</p>
    </div>
  );
}

// ── Onglet Vue d'ensemble ─────────────────────────────────────────────────────
function OngletVisites({ stats }: { stats: typeof DEMO_STATS }) {
  const { totaux, parJour, devices, navigateurs } = stats;
  const totalDevices = devices.reduce((s, d) => s + Number(d.total), 0);
  const totalNav = navigateurs.reduce((s, n) => s + Number(n.total), 0);

  const deviceCouleurs = ['#2d6a9f', '#10b981', '#f59e0b'];
  const navCouleurs    = ['#2d6a9f', '#6366f1', '#f97316', '#14b8a6', '#ec4899'];

  const deviceIcons: Record<string, string> = { desktop: '🖥️', mobile: '📱', tablet: '📱' };
  const deviceLabels: Record<string, string> = { desktop: 'Ordinateur', mobile: 'Mobile', tablet: 'Tablette' };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      {/* KPIs */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '14px' }}>
        <KPI icon="👁️" titre="Visites totales"     valeur={fmt(totaux.total_visites)}      sous="Période sélectionnée"                   couleur={T.accent}   />
        <KPI icon="👤" titre="Visiteurs uniques"   valeur={fmt(totaux.visiteurs_uniques)}  sous="Sessions distinctes"                    couleur="#6366f1"    />
        <KPI icon="🕐" titre="Actifs aujourd'hui"  valeur={fmt(totaux.actifs_aujourdhui)} sous="Visiteurs des 24 dernières heures"       couleur={T.warning}  />
        <KPI icon="⏱️" titre="Durée moyenne"        valeur={fmtDuree(totaux.duree_moyenne)} sous={`${Number(totaux.pages_par_session || 0).toFixed(1)} pages/session`} couleur="#ec4899" />
      </div>

      {/* Graphe courbe */}
      <div style={{ backgroundColor: T.card, borderRadius: '12px', border: `1px solid ${T.border}`, padding: '24px' }}>
        <h3 style={{ fontSize: '13px', fontWeight: '700', color: T.accent, margin: '0 0 20px 0', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
          📈 Évolution des visites
        </h3>
        <LineChart data={parJour} />
      </div>

      {/* Devices + Navigateurs */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
        {/* Devices */}
        <div style={{ backgroundColor: T.card, borderRadius: '12px', border: `1px solid ${T.border}`, padding: '24px' }}>
          <h3 style={{ fontSize: '13px', fontWeight: '700', color: T.accent, margin: '0 0 20px 0', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
            💻 Appareils utilisés
          </h3>
          <DonutChart
            data={devices.map(d => ({ label: deviceLabels[d.device] || d.device, value: Number(d.total) }))}
            total={totalDevices}
            couleurs={deviceCouleurs}
          />
          <div style={{ marginTop: '20px', display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {devices.map((d, i) => {
              const pct = totalDevices > 0 ? (Number(d.total) / totalDevices) * 100 : 0;
              return (
                <div key={i}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                    <span style={{ fontSize: '12px', fontWeight: '600', color: T.text }}>{deviceIcons[d.device] || '📱'} {deviceLabels[d.device] || d.device}</span>
                    <span style={{ fontSize: '12px', color: T.textLight }}>{fmt(d.total)} ({Math.round(pct)}%)</span>
                  </div>
                  <div style={{ backgroundColor: '#f0f0f0', borderRadius: '4px', height: '6px', overflow: 'hidden' }}>
                    <div style={{ backgroundColor: deviceCouleurs[i], height: '100%', width: `${pct}%`, borderRadius: '4px' }} />
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Navigateurs */}
        <div style={{ backgroundColor: T.card, borderRadius: '12px', border: `1px solid ${T.border}`, padding: '24px' }}>
          <h3 style={{ fontSize: '13px', fontWeight: '700', color: T.accent, margin: '0 0 20px 0', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
            🌐 Navigateurs
          </h3>
          <DonutChart
            data={navigateurs.map(n => ({ label: n.navigateur, value: Number(n.total) }))}
            total={totalNav}
            couleurs={navCouleurs}
          />
          <div style={{ marginTop: '20px', display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {navigateurs.map((n, i) => {
              const pct = totalNav > 0 ? (Number(n.total) / totalNav) * 100 : 0;
              return (
                <div key={i}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                    <span style={{ fontSize: '12px', fontWeight: '600', color: T.text }}>{n.navigateur}</span>
                    <span style={{ fontSize: '12px', color: T.textLight }}>{fmt(n.total)} ({Math.round(pct)}%)</span>
                  </div>
                  <div style={{ backgroundColor: '#f0f0f0', borderRadius: '4px', height: '6px', overflow: 'hidden' }}>
                    <div style={{ backgroundColor: navCouleurs[i % navCouleurs.length], height: '100%', width: `${pct}%`, borderRadius: '4px' }} />
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Onglet Pages ──────────────────────────────────────────────────────────────
function OngletPages({ stats }: { stats: typeof DEMO_STATS }) {
  const { pagesTop } = stats;
  const [page, setPage] = useState(1);
  const [parPage, setParPage] = useState(50);

  const max = Math.max(...pagesTop.map(p => Number(p.visites)), 1);
  const totalPages = Math.ceil(pagesTop.length / parPage);
  const debut = (page - 1) * parPage;
  const pageData = pagesTop.slice(debut, debut + parPage);

  // Reset page quand on change parPage
  const changerParPage = (n: number) => { setParPage(n); setPage(1); };

  return (
    <div style={{ backgroundColor: T.card, borderRadius: '12px', border: `1px solid ${T.border}`, overflow: 'hidden' }}>
      {/* En-tête */}
      <div style={{ padding: '16px 24px', borderBottom: `2px solid ${T.accent}`, backgroundColor: '#f8fafc', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h3 style={{ fontSize: '13px', fontWeight: '700', color: T.accent, margin: 0, textTransform: 'uppercase', letterSpacing: '0.5px' }}>
          📄 Pages les plus visitées
        </h3>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <span style={{ fontSize: '12px', color: T.textLight }}>{pagesTop.length} pages au total</span>
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
            <span style={{ fontSize: '12px', color: T.textLight }}>Afficher</span>
            {[25, 50, 100].map(n => (
              <button key={n} onClick={() => changerParPage(n)} style={{
                padding: '4px 10px', fontSize: '12px', fontWeight: '700', cursor: 'pointer',
                border: `1px solid ${parPage === n ? T.accent : T.border}`,
                backgroundColor: parPage === n ? T.accent : 'white',
                color: parPage === n ? 'white' : T.textLight,
                borderRadius: '6px', transition: 'all 0.15s',
              }}>{n}</button>
            ))}
          </div>
        </div>
      </div>

      {/* Tableau */}
      <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '13px' }}>
        <thead>
          <tr style={{ backgroundColor: '#f8fafc' }}>
            {['#', 'Page', 'Titre', 'Visites', 'Visiteurs uniques', 'Durée moy.', 'Popularité'].map(h => (
              <th key={h} style={{ padding: '10px 16px', textAlign: 'left', fontWeight: '600', color: T.textLight, borderBottom: `1px solid ${T.border}`, fontSize: '11px', textTransform: 'uppercase', letterSpacing: '0.4px' }}>{h}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {pageData.map((p, i) => {
            const rang = debut + i + 1;
            const pct = (Number(p.visites) / max) * 100;
            return (
              <tr key={i} style={{ backgroundColor: i % 2 === 0 ? 'white' : '#fafafa' }}>
                <td style={{ padding: '12px 16px', color: T.textLight, fontWeight: '700', fontSize: '12px' }}>#{rang}</td>
                <td style={{ padding: '12px 16px' }}>
                  <code style={{ backgroundColor: '#f0f2f5', padding: '2px 8px', borderRadius: '4px', fontSize: '11px', color: T.accent, fontFamily: 'monospace' }}>
                    {p.page}
                  </code>
                </td>
                <td style={{ padding: '12px 16px', fontWeight: '600', color: T.text }}>{p.titre || '—'}</td>
                <td style={{ padding: '12px 16px', fontWeight: '700', color: T.text }}>{fmt(p.visites)}</td>
                <td style={{ padding: '12px 16px', color: T.textLight }}>{fmt(p.visiteurs_uniques)}</td>
                <td style={{ padding: '12px 16px', color: T.textLight }}>{fmtDuree(p.duree_moy)}</td>
                <td style={{ padding: '12px 16px', minWidth: '120px' }}>
                  <div style={{ backgroundColor: '#f0f0f0', borderRadius: '4px', height: '8px', overflow: 'hidden' }}>
                    <div style={{ backgroundColor: T.accent, height: '100%', width: `${pct}%`, borderRadius: '4px' }} />
                  </div>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>

      {/* Pagination */}
      {totalPages > 1 && (
        <div style={{ padding: '14px 24px', borderTop: `1px solid ${T.border}`, display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: '#f8fafc' }}>
          <span style={{ fontSize: '12px', color: T.textLight }}>
            Affichage {debut + 1}–{Math.min(debut + parPage, pagesTop.length)} sur {pagesTop.length}
          </span>
          <div style={{ display: 'flex', gap: '4px', alignItems: 'center' }}>
            <button onClick={() => setPage(1)} disabled={page === 1} style={btnStyle(page === 1)}>«</button>
            <button onClick={() => setPage(p => p - 1)} disabled={page === 1} style={btnStyle(page === 1)}>‹</button>
            {Array.from({ length: Math.min(totalPages, 7) }, (_, i) => {
              let p: number;
              if (totalPages <= 7) p = i + 1;
              else if (page <= 4) p = i + 1;
              else if (page >= totalPages - 3) p = totalPages - 6 + i;
              else p = page - 3 + i;
              return (
                <button key={p} onClick={() => setPage(p)} style={btnStyle(false, p === page)}>
                  {p}
                </button>
              );
            })}
            <button onClick={() => setPage(p => p + 1)} disabled={page === totalPages} style={btnStyle(page === totalPages)}>›</button>
            <button onClick={() => setPage(totalPages)} disabled={page === totalPages} style={btnStyle(page === totalPages)}>»</button>
          </div>
        </div>
      )}
    </div>
  );
}

function btnStyle(disabled: boolean, active = false) {
  return {
    padding: '5px 10px', fontSize: '12px', fontWeight: '600', cursor: disabled ? 'default' : 'pointer',
    border: `1px solid ${active ? T.accent : T.border}`,
    backgroundColor: active ? T.accent : disabled ? '#f5f5f5' : 'white',
    color: active ? 'white' : disabled ? '#ccc' : T.text,
    borderRadius: '6px', minWidth: '32px', transition: 'all 0.15s',
  } as React.CSSProperties;
}

// ── Onglet Géographie ─────────────────────────────────────────────────────────
function OngletGeo({ stats }: { stats: typeof DEMO_STATS }) {
  const { paysTop, provincesTop } = stats;
  const max = Math.max(...paysTop.map(p => Number(p.visites)), 1);
  const total = paysTop.reduce((s, p) => s + Number(p.visites), 0);

  // Construire les bulles à partir des vraies données
  const provinceBulles = provincesTop
    .map(p => {
      const pos = PROVINCES_POSITIONS[p.province];
      if (!pos) return null;
      return { code: p.province, nom: pos.nom, x: pos.x, y: pos.y, visites: Number(p.visites) };
    })
    .filter(Boolean) as { code: string; nom: string; x: number; y: number; visites: number }[];

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      {/* Carte Canada */}
      <div style={{ backgroundColor: T.card, borderRadius: '12px', border: `1px solid ${T.border}`, padding: '24px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h3 style={{ fontSize: '13px', fontWeight: '700', color: T.accent, margin: 0, textTransform: 'uppercase', letterSpacing: '0.5px' }}>
            🗺️ Distribution au Canada
          </h3>
          <span style={{ fontSize: '12px', color: T.textLight, backgroundColor: T.accentL, padding: '4px 10px', borderRadius: '20px', fontWeight: '600' }}>
            Taille = nombre de visites
          </span>
        </div>
        <CarteCanada provinces={provinceBulles.length > 0 ? provinceBulles : []} />
      </div>

      {/* Tableau pays */}
      <div style={{ backgroundColor: T.card, borderRadius: '12px', border: `1px solid ${T.border}`, overflow: 'hidden' }}>
        <div style={{ padding: '16px 24px', borderBottom: `2px solid ${T.accent}`, backgroundColor: '#f8fafc' }}>
          <h3 style={{ fontSize: '13px', fontWeight: '700', color: T.accent, margin: 0, textTransform: 'uppercase', letterSpacing: '0.5px' }}>🌍 Visites par pays</h3>
        </div>
        {paysTop.map((p, i) => {
          const pct = (Number(p.visites) / max) * 100;
          const partTotale = total > 0 ? ((Number(p.visites) / total) * 100).toFixed(1) : '0';
          return (
            <div key={i} style={{ padding: '14px 24px', borderBottom: i < paysTop.length - 1 ? `1px solid #f5f5f5` : 'none', display: 'flex', alignItems: 'center', gap: '16px' }}>
              <span style={{ fontSize: '20px', minWidth: '28px' }}>
                {p.pays === 'CA' ? '🇨🇦' : p.pays === 'US' ? '🇺🇸' : p.pays === 'FR' ? '🇫🇷' : p.pays === 'BE' ? '🇧🇪' : p.pays === 'CH' ? '🇨🇭' : '🌐'}
              </span>
              <div style={{ minWidth: '140px' }}>
                <span style={{ fontSize: '13px', fontWeight: '700', color: T.text }}>{PAYS_NOMS[p.pays] || p.pays}</span>
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ backgroundColor: '#f0f0f0', borderRadius: '4px', height: '8px', overflow: 'hidden' }}>
                  <div style={{ backgroundColor: i === 0 ? T.accent : `${T.accent}${80 - i * 12}`, height: '100%', width: `${pct}%`, borderRadius: '4px' }} />
                </div>
              </div>
              <span style={{ fontSize: '13px', fontWeight: '700', color: T.text, minWidth: '60px', textAlign: 'right' }}>{fmt(p.visites)}</span>
              <span style={{ fontSize: '12px', color: T.textLight, minWidth: '45px', textAlign: 'right' }}>{partTotale}%</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Onglet Sources ────────────────────────────────────────────────────────────
function OngletSources({ stats }: { stats: typeof DEMO_STATS }) {
  const { referents } = stats;
  const total = referents.reduce((s, r) => s + Number(r.visites), 0);
  const max   = Math.max(...referents.map(r => Number(r.visites)), 1);

  const couleurs: Record<string, string> = {
    Direct: '#2d6a9f', Google: '#ea4335', Facebook: '#1877f2',
    Instagram: '#e1306c', TikTok: '#010101', 'Twitter/X': '#1da1f2', YouTube: '#ff0000', Autre: '#6b7280',
  };
  const icons: Record<string, string> = {
    Direct: '🔗', Google: '🔍', Facebook: '📘',
    Instagram: '📸', TikTok: '🎵', 'Twitter/X': '🐦', YouTube: '▶️', Autre: '🌐',
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      {/* Donut + barres */}
      <div style={{ display: 'grid', gridTemplateColumns: '380px 1fr', gap: '16px' }}>
        <div style={{ backgroundColor: T.card, borderRadius: '12px', border: `1px solid ${T.border}`, padding: '24px' }}>
          <h3 style={{ fontSize: '13px', fontWeight: '700', color: T.accent, margin: '0 0 20px 0', textTransform: 'uppercase', letterSpacing: '0.5px' }}>🔗 Répartition des sources</h3>
          <DonutChart
            data={referents.map(r => ({ label: r.source, value: Number(r.visites) }))}
            total={total}
            couleurs={referents.map(r => couleurs[r.source] || T.accent)}
          />
        </div>

        <div style={{ backgroundColor: T.card, borderRadius: '12px', border: `1px solid ${T.border}`, padding: '24px' }}>
          <h3 style={{ fontSize: '13px', fontWeight: '700', color: T.accent, margin: '0 0 20px 0', textTransform: 'uppercase', letterSpacing: '0.5px' }}>📊 Visites par source</h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
            {referents.map((r, i) => {
              const pct = total > 0 ? ((Number(r.visites) / total) * 100) : 0;
              const barW = (Number(r.visites) / max) * 100;
              return (
                <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <span style={{ fontSize: '16px', minWidth: '22px' }}>{icons[r.source] || '🌐'}</span>
                  <span style={{ fontSize: '12px', fontWeight: '600', color: T.text, minWidth: '90px' }}>{r.source}</span>
                  <div style={{ flex: 1 }}>
                    <div style={{ backgroundColor: '#f0f0f0', borderRadius: '4px', height: '10px', overflow: 'hidden' }}>
                      <div style={{ backgroundColor: couleurs[r.source] || T.accent, height: '100%', width: `${barW}%`, borderRadius: '4px', transition: 'width 0.5s' }} />
                    </div>
                  </div>
                  <span style={{ fontSize: '12px', fontWeight: '700', color: T.text, minWidth: '50px', textAlign: 'right' }}>{fmt(r.visites)}</span>
                  <span style={{ fontSize: '11px', color: T.textLight, minWidth: '40px', textAlign: 'right' }}>{pct.toFixed(1)}%</span>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Composant principal ───────────────────────────────────────────────────────
export default function AnalytiqueGestionnaire({ gestionnaireId }: Props) {
  const [onglet, setOnglet] = useState<'visites' | 'pages' | 'geo' | 'sources'>('visites');
  const [periode, setPeriode] = useState('30');
  const [stats, setStats] = useState<typeof DEMO_STATS | null>(null);
  const [loading, setLoading] = useState(true);
  const [demo, setDemo] = useState(false);

  useEffect(() => {
    setLoading(true);
    const token = localStorage.getItem('token');
    // gestionnaire_id n'est jamais envoyé ici : le backend le déduit uniquement
    // du token (req.user.id), donc impossible de lire les stats d'un autre
    // gestionnaire même en modifiant la requête depuis le navigateur.
    fetch(`${API_BASE}/analytique/stats?periode=${periode}`, {
      credentials: 'include', headers: { Authorization: `Bearer ${token}` },
    })
      .then(r => r.ok ? r.json() : null)
      .then(data => {
        if (data && Number(data.totaux?.total_visites) > 0) {
          setStats(data);
          setDemo(false);
        } else {
          setStats(DEMO_STATS);
          setDemo(true);
        }
      })
      .catch(() => { setStats(DEMO_STATS); setDemo(true); })
      .finally(() => setLoading(false));
  }, [periode, gestionnaireId]);

  const onglets = [
    { id: 'visites',  label: '🌐 Vue d\'ensemble', },
    { id: 'pages',    label: '📄 Pages visitées',  },
    { id: 'geo',      label: '🗺️ Géographie',      },
    { id: 'sources',  label: '🔗 Sources de trafic'},
  ] as const;

  return (
    <div style={{ padding: '28px 32px', maxWidth: '1300px' }}>
      {/* En-tête */}
      <div style={{ marginBottom: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
        <div>
          <h1 style={{ fontSize: '20px', fontWeight: '800', margin: '0 0 4px 0', color: T.text, textTransform: 'uppercase', letterSpacing: '0.5px' }}>
            📈 Analytique du site
          </h1>
          <p style={{ fontSize: '13px', color: T.textLight, margin: 0 }}>
            Trafic, comportement des visiteurs et sources
          </p>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          {demo && (
            <div style={{ backgroundColor: '#fef9c3', border: '1px solid #d97706', borderRadius: '8px', padding: '6px 14px', fontSize: '12px', fontWeight: '600', color: '#92400e' }}>
              ⚠️ Données de démonstration — en attente de vrais visiteurs
            </div>
          )}
          <select value={periode} onChange={e => setPeriode(e.target.value)}
            style={{ padding: '8px 14px', borderRadius: '8px', border: `1px solid ${T.border}`, fontSize: '13px', fontWeight: '600', color: T.text, backgroundColor: 'white', cursor: 'pointer' }}>
            <option value="7">7 derniers jours</option>
            <option value="30">30 derniers jours</option>
            <option value="90">90 derniers jours</option>
            <option value="365">12 derniers mois</option>
          </select>
        </div>
      </div>

      {/* Onglets */}
      <div style={{ display: 'flex', gap: '4px', borderBottom: `2px solid ${T.border}`, marginBottom: '24px' }}>
        {onglets.map(o => (
          <button key={o.id} onClick={() => setOnglet(o.id)}
            style={{
              padding: '10px 18px', border: 'none', cursor: 'pointer',
              borderRadius: '8px 8px 0 0', fontSize: '13px',
              fontWeight: onglet === o.id ? '700' : '500',
              backgroundColor: onglet === o.id ? T.card : 'transparent',
              color: onglet === o.id ? T.accent : T.textLight,
              borderBottom: onglet === o.id ? `2px solid ${T.accent}` : '2px solid transparent',
              marginBottom: '-2px', transition: 'all 0.15s',
            }}>
            {o.label}
          </button>
        ))}
      </div>

      {/* Contenu */}
      {loading ? (
        <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '40vh' }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '40px', marginBottom: '12px' }}>📊</div>
            <p style={{ color: T.textLight }}>Chargement des données...</p>
          </div>
        </div>
      ) : stats ? (
        <>
          {onglet === 'visites'  && <OngletVisites  stats={stats} />}
          {onglet === 'pages'    && <OngletPages    stats={stats} />}
          {onglet === 'geo'      && <OngletGeo      stats={stats} />}
          {onglet === 'sources'  && <OngletSources  stats={stats} />}
        </>
      ) : null}
    </div>
  );
}